require "config.TabConfig"
require "ui.window.GUIIllustrationTab"
require "ui.window.GUIIllustrationList"

local GUIIllustration = class("UIIllustration", IGUILayout)

function GUIIllustration:onLoad()
    self.Tabs = {}
    self.Lists = {}
    self.selectTab = 0
    self.isShown = false

    self.llView = self:getChildWindow("LuckySkyHallIllustrated-Bg", GUIType.Layout)
    self:getChildWindow("LuckySkyHallIllustrated-Title", GUIType.StaticText):SetText(Lang:getString("lucky_sky_illustration_title"))
    self.ltTabs = self:getChildWindow("LuckySkyHallIllustrated-Tabs", GUIType.List)
    self.llLists = self:getChildWindow("LuckySkyHallIllustrated-Item-List", GUIType.Layout)

    self.ltTabs:SetInterval(2)
    self.llView:registerEvent(GUIEvent.Click, function()
        self:hide()
    end)

    self:initTabsAndLists()
end

function GUIIllustration:initTabsAndLists()
    local tabs = TabConfig:getTabs()
    local isFirst = true
    local num = 1
    local tabWidth = self.ltTabs:GetPixelSize().x
    for _, tab in pairs(tabs) do
        local btnTab = GUIIllustrationTab.new("LuckySkyHallIllustratedTab.json")
        local list = GUIIllustrationList.new("LuckySkyHallIllustratedList.json")

        if isFirst then
            tab.isSelect = true
            self.selectTab = tab.id
            isFirst = false
        end

        self.ltTabs:AddItem(btnTab.root)
        btnTab:initTab(tab, tabWidth)
        self.Tabs[tab.id] = btnTab

        self.llLists:AddChildWindow(list.root)
        list:initList(tab.id)
        list:setVisible(false)
        self.Lists[tab.id] = list

        num = num + 1
    end

    self.Lists[self.selectTab]:setVisible(true)
end

function GUIIllustration:onTabClick(tabId)
    if not self.Tabs[tabId] or not self.Lists[tabId] then
        return
    end
    self.Tabs[self.selectTab]:changeStatus(false)
    self.Lists[self.selectTab]:setVisible(false)

    self.selectTab = tabId
    self.Tabs[self.selectTab]:changeStatus(true)
    self.Lists[self.selectTab]:setVisible(true)
end

return GUIIllustration